import sys

def solve(data: str) -> str:
    values = [int(token) for token in data.split()]
    squares = [value * value for value in values if value % 2 == 0]
    return ' '.join(map(str, squares))

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
